import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";

/// @title BittensorCrossChainMessenger
/// @notice LayerZero OApp for cross-chain messaging between BSC and Bittensor EVM.
/// @dev Deploy this same contract on both chains and set the peer to the other chain's deployment.
contract BittensorCrossChainMessenger is OApp, OAppOptionsType3 {
    /// @notice Message type for sending a payload (used for enforced options).
    uint16 public constant MSG_PAYLOAD = 1;

    /// @notice Last payload received from any remote chain (for simple testing).
    bytes public lastPayload;

    /// @notice Emitted when a message is sent to a remote chain.
    event MessageSent(uint32 dstEid, bytes payload, address sender);
    /// @notice Emitted when a message is received from a remote chain.
    event MessageReceived(uint32 srcEid, bytes32 sender, bytes payload);

    /// @param _endpoint Local LayerZero EndpointV2 address (chain-specific).
    /// @param _owner Owner allowed to set peers and options.
    constructor(address _endpoint, address _owner) OApp(_endpoint, _owner) Ownable(_owner) {}

    /// @notice Quote fee for sending a payload to a destination chain.
    function quoteSend(
        uint32 _dstEid,
        bytes calldata _payload,
        bytes calldata _options,
        bool _payInLzToken
    ) external view returns (MessagingFee memory fee) {
        fee = _quote(
            _dstEid,
            _payload,
            combineOptions(_dstEid, MSG_PAYLOAD, _options),
            _payInLzToken
        );
    }

    /// @notice Send an arbitrary payload to the peer OApp on another chain.
    /// @param _dstEid Destination chain LayerZero endpoint ID (e.g. 30102 for BSC).
    /// @param _payload ABI-encoded or raw bytes to send.
    /// @param _options Execution options (e.g. gas for destination); can pass "0x".
    function send(
        uint32 _dstEid,
        bytes calldata _payload,
        bytes calldata _options
    ) external payable {
        _lzSend(
            _dstEid,
            _payload,
            combineOptions(_dstEid, MSG_PAYLOAD, _options),
            MessagingFee(msg.value, 0),
            payable(msg.sender)
        );
        emit MessageSent(_dstEid, _payload, msg.sender);
    }

    /// @notice Receive path: decode and store payload; override to add custom logic.
    function _lzReceive(
        Origin calldata _origin,
        bytes32 /*_guid*/,
        bytes calldata _message,
        address /*_executor*/,
        bytes calldata /*_extraData*/
    ) internal override {
        lastPayload = _message;
        emit MessageReceived(_origin.srcEid, _origin.sender, _message);
    }
}

