// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";

/// @title CrossChainMessageStore
/// @notice Optional second contract: stores message history and metadata for the Bittensor cross-chain messenger.
/// @dev The OApp (BittensorCrossChainMessenger) can push entries here on receive, or this can be used by off-chain indexers.
contract CrossChainMessageStore is Ownable {
    struct StoredMessage {
        uint32 srcEid;
        bytes32 sender;
        bytes payload;
        uint256 blockNumber;
        uint256 index;
    }

    /// @notice Messenger contract allowed to push messages.
    address public messenger;

    /// @notice All stored messages (indexed by chain and sequence).
    StoredMessage[] public messages;

    /// @notice Last message index per source endpoint ID.
    mapping(uint32 srcEid => uint256) public lastIndexByEid;

    event MessageStored(uint256 indexed index, uint32 srcEid, bytes32 sender, uint256 blockNumber);
    event MessengerUpdated(address indexed previousMessenger, address indexed newMessenger);

    constructor(address _owner) Ownable(_owner) {}

    /// @notice Restrict storage to the OApp messenger only.
    modifier onlyMessenger() {
        require(msg.sender == messenger, "CrossChainMessageStore: only messenger");
        _;
    }

    /// @notice Set the allowed messenger (BittensorCrossChainMessenger address).
    function setMessenger(address _messenger) external onlyOwner {
        address prev = messenger;
        messenger = _messenger;
        emit MessengerUpdated(prev, _messenger);
    }

    /// @notice Store a received cross-chain message (called by the OApp or a relayer).
    function storeMessage(
        uint32 _srcEid,
        bytes32 _sender,
        bytes calldata _payload
    ) external onlyMessenger returns (uint256 index) {
        index = messages.length;
        messages.push(
            StoredMessage({
                srcEid: _srcEid,
                sender: _sender,
                payload: _payload,
                blockNumber: block.number,
                index: index
            })
        );
        lastIndexByEid[_srcEid] = index;
        emit MessageStored(index, _srcEid, _sender, block.number);
        return index;
    }

    /// @notice Number of stored messages.
    function messageCount() external view returns (uint256) {
        return messages.length;
    }

    /// @notice Get a message by index.
    function getMessage(uint256 _index) external view returns (StoredMessage memory) {
        require(_index < messages.length, "CrossChainMessageStore: index out of bounds");
        return messages[_index];
    }
}

